import anthropic, base64, time
from PIL import ImageGrab
import pyautogui

client = anthropic.Anthropic()

def screenshot_b64() -> str:
    """Capture the full screen and return a base64-encoded PNG."""
    img = ImageGrab.grab()
    import io
    buf = io.BytesIO()
    img.save(buf, format="PNG")
    return base64.standard_b64encode(buf.getvalue()).decode("utf-8")

def dispatch_action(action: dict) -> None:
    """Execute a single tool_use action produced by Claude."""
    kind = action["type"]
    if kind == "computer":
        sub = action["action"]
        if sub == "screenshot":
            return  # handled by caller: re-captures fresh frame
        elif sub == "left_click":
            pyautogui.click(action["coordinate"][0], action["coordinate"][1])
        elif sub == "double_click":
            pyautogui.doubleClick(action["coordinate"][0], action["coordinate"][1])
        elif sub == "right_click":
            pyautogui.rightClick(action["coordinate"][0], action["coordinate"][1])
        elif sub == "type":
            pyautogui.typewrite(action["text"], interval=0.04)
        elif sub == "key":
            pyautogui.hotkey(*action["key"].split("+"))
        elif sub == "scroll":
            pyautogui.scroll(action["direction"] == "up" and 3 or -3,
                             x=action["coordinate"][0], y=action["coordinate"][1])
        elif sub == "drag":
            pyautogui.dragTo(action["endCoordinate"][0], action["endCoordinate"][1],
                             duration=0.5, button="left")
        time.sleep(0.3)  # brief settle before next capture
